B.a13=new A.eP("Klmaty","\u0643\u0644\u0645\u0627\u062a\u064a","\u0643\u0644\u0645\u0627\u062a\u064a \u0647\u0648 \u062a\u0637\u0628\u064a\u0642 \u062a\u0639\u0644\u064a\u0645\u064a \u0644\u0644\u0623\u0637\u0641\u0627\u0644 \u064a\u062c\u0645\u0639 \u0628\u064a\u0646 \u0627\u0644\u0645\u062a\u0639\u0629 \u0648\u0627\u0644\u062a\u0639\u0644\u0645 \u0641\u064a \u0628\u064a\u0626\u0629 \u0622\u0645\u0646\u0629.\n\u0628\u0627\u0644\u0635\u0648\u0631 \u0627\u0644\u0645\u0644\u0648\u0646\u0629\u060c \u0627\u0644\u0623\u0635\u0648\u0627\u062a \u0627\u0644\u0645\u0645\u064a\u0632\u0629\u060c \u0648\u0627\u0644\u0642\u0635\u0635 \u0627\u0644\u0634\u064a\u0642\u0629\u060c \u0633\u064a\u0633\u062a\u0645\u062a\u0639 \u0637\u0641\u0644\u0643 \u0628\u0627\u0643\u062a\u0634\u0627\u0641 \u0627\u0644\u0643\u0644\u0645\u0627\u062a \u0648\u0627\u0644\u062d\u0631\u0648\u0641 \u0628\u0637\u0631\u064a\u0642\u0629 \u0633\u0647\u0644\u0629 \u0648\u0645\u0633\u0644\u064a\u0629.\n","Klmaty is an educational app designed to make learning fun, safe, and interactive for children. With colorful words, engaging sounds, and exciting stories, your child will enjoy discovering language while playing.","assets/images/projects/klmaty.webp",u.o,u.o,null)
